var gSimInet;

function lingoXtraNoDebug() {
  _player.debugPlaybackEnabled = 0;
  var myFile = new xtra("fileio");
  openfile(myFile, "lingo.ini", 1);
  if (myFile.status() === 0) {
    quit();
  }
  myFile = null;
}

function lingoXtraInit() {
  _player.debugPlaybackEnabled = 1;
  caluMD5_register("I", "agree with the usage terms");
  _movie.timeoutLength = 216000;
  _movie.timeoutScript = "setInactive";
  gSimInet = new xtra("simInet");
}

function getPCInfo() {
  var bdi = String(baDiskInfo(baSysFolder("windows"), "number"));
  var dot = bdi.indexOf(".");
  if (dot > 0) {
    bdi = bdi.substring(0, dot);
  }
  var qs = "mid=" + bdi + baCpuInfo("vendor") + baCpuInfo("type") + baCpuInfo("model");
  qs += "&nid=" + To3GetMacAddress().substring(0, 17);
  qs += "&prid=" + baReadRegString(
    "SOFTWARE\\Microsoft\\Windows\\CurrentVersion",
    "ProductId", "NoProductId", "HKEY_LOCAL_MACHINE"
  );
  qs += "&cna=" + baComputerName();
  return qs;
}

